INSERT INTO `questions` (`id`, `q_id`, `text`, `weight`, `created_at`, `updated_at`) VALUES
(184, 2, 'რა არის პასიური გათბობის/გაგრილების სისტემების ძირითადი პრინციპი?', NULL, '2025-01-14 12:25:21', '2025-02-23 01:45:12'),
(203, 1, 'რა არის \"არქიტექტურული საქმიანობის შესახებ\" საქართველოს კანონის მთავარი მიზანი?', NULL, '2025-01-14 12:25:21', '2025-01-14 12:25:21'),
(204, 2, 'რას გულისხმობს \"არქიტექტურული საქმიანობა\" ამ კანონის მიხედვით?', NULL, '2025-01-14 12:25:21', '2025-01-14 12:25:21'),
(205, 3, 'რას წარმოადგენს არქიტექტურული პროექტი?', NULL, '2025-01-14 12:25:21', '2025-01-14 12:25:21'),
