(207, 5, 'რა უფლება აქვს არქიტექტორს დამკვეთთან დადებული ხელშეკრულების საფუძველზე?', NULL, '2025-01-14 12:25:21', '2025-01-14 12:25:21'),
(208, 6, 'რა მოვალეობა აკისრია არქიტექტორს არქიტექტურული საქმიანობის განხორციელებისას?', NULL, '2025-01-14 12:25:21', '2025-01-14 12:25:21'),
(209, 7, 'რა უფლება აქვთ უცხო ქვეყნის ფიზიკურ და იურიდიულ პირებს საქართველოში არქიტექტურული საქმიანობის განხორციელების კუთხით?', NULL, '2025-01-14 12:25:21', '2025-01-14 12:25:21'),
(211, 9, 'რა არის სამსახურებრივი ნაწარმოები?', NULL, '2025-01-14 12:25:21', '2025-01-14 12:25:21'),
