(2315, NULL, 'რამდენი უნდა იყოს დერეფნის მინიმალური სიგანე, როდესაც დერეფანი ემსახურება დწ-2 ჯგუფის ფართობებს, სადაც აუცილებელია საწოლების გადაადგილება?', NULL, '2025-02-10 16:37:52', '2025-07-10 09:27:09'),
(2316, NULL, 'რამდენ კვადრატულ მეტრს არ უნდა აღემატებოდეს სც-2 ჯგუფის მრავალბინიანი საცხოვრებელი შენობის,  მე-8 სართულის ფართობი (იატაკის მთლიანი ფართობის შესაბამისად), თუ შენობა კლასიფიცირებულია, როგორც სც-2 ჯგუფის მრავალბინიანი საცხოვრებელი შენობა, მოიცავს საცხოვრებელ ერთეულებს, გააჩნია მიწის დონის ზედა ოთხი ან მეტი სართული, მაგრამ არაუმეტეს რვა სართული და თითოეულ საცხოვრებელ ერთეულთან მიდგომა შესაძლებელია სახანძრო მანქანის მეშვეობით, თუ სართულს ემსახურება ერთი გასასვლელი ან გასასვლელთან მისადგომი?', NULL, '2025-02-10 16:38:48', '2025-07-25 13:18:34'),
(2317, NULL, 'რამდენი უნდა იყოს გასასვლელთან მისადგომი მაქსიმალური სავალი მანძილი, სც-2 ჯგუფის მრავალბინიან საცხოვრებელი შენობის მე-5 სართულზე, თუ შენობა კლასიფიცირებულია, როგორც სც-2 ჯგუფის მრავალბინიანი საცხოვრებელი შენობა, მოიცავს საცხოვრებელ ერთეულებს, გააჩნია მიწის დონის ზედა ოთხი ან მეტი სართული, მაგრამ არაუმეტეს რვა სართული და თითოეულ საცხოვრებელ ერთეულთან მიდგომა შესაძლებელია სახანძრო მანქანის მეშვეობით, თუ სართულს ემსახურება ერთი გასასვლელი ან გასასვლელთან მისადგომი?', NULL, '2025-02-10 16:40:12', '2025-07-25 13:19:02'),
(2318, NULL, 'რა მინიმალური რაოდენობის გასასვლელი ან გასასვლელთან მისადგომი ესაჭიროება მესამე სართულზე არსებულ სქ დაკავებულობას, თუ მაქსიმალური დაკავებულობის დატვირთვა სართულზე შეადგენს 20 დამკავებელს და გასასვლელთან მისადგომი მაქსიმალური სავალი მანძილი 15 მეტრია?', NULL, '2025-02-10 16:41:58', '2025-07-25 13:19:29'),
